import './Pagination.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import type { PaginationProps } from './Pagination.types';
import { PaginationCollapsible } from './PaginationCollapsible';
import { PaginationStandard } from './PaginationStandard';

export const Pagination: FC<PaginationProps> = ({
	count = 1,
	page = 1,
	siblingCount = 3,
	collapsed = true,
	onChange,
	...props
}) => {
	/** Если количество страниц меньше 1, то всегда отображаем первый номер страницы*/
	const calcedCount = useMemo(() => {
		if (count <= 0) {
			return 1;
		}
		return count;
	}, [count]);

	/** Отображать количество соседних страниц (siblingCount) <= общего количества страниц
	 * Невозможность отобразить, номера страниц которых нет.
	 */
	const calcedSiblingCount = useMemo(() => {
		if (siblingCount <= 0) {
			return 0;
		}

		if (siblingCount > count) {
			return count;
		}

		return siblingCount;
	}, [count, siblingCount]);

	/**
	 * Валидный номер страницы.
	 */
	const calcedPage = useMemo(() => {
		/** Устанавливает максимальное значение равным количеству всех страниц */
		if (page > count) {
			return count;
		}
		/** Устанавливает минимальное значение равным 1 */
		if (page <= 0) {
			return 1;
		}
		return page;
	}, [count, page]);

	return (
		<>
			{collapsed && (
				<PaginationCollapsible
					data-testid="Pagination"
					count={calcedCount}
					page={calcedPage}
					onChange={onChange}
					siblingCount={calcedSiblingCount}
					{...props}
				/>
			)}
			{!collapsed && (
				<PaginationStandard
					data-testid="Pagination"
					count={calcedCount}
					page={calcedPage}
					onChange={onChange}
					{...props}
				/>
			)}
		</>
	);
};
